                    nativeControls: (defaults.isIOS || defaults.isIPad) ? !displayFakeFullscreenPlayer : false,
                    autoFullscreen: {
                        android: defaults.isAndroid,
                        ios: (defaults.isIOS || defaults.isIPad),
